import numpy as np

class BaggingRegressor:
    def __init__(self, n_estimators: int = 10, seed: int = None):
        self.n_estimators = n_estimators
        self.seed = seed
        self.estimator_means_ = []

    def fit(self, X: np.ndarray, y: np.ndarray) -> 'BaggingRegressor':
        rng = np.random.default_rng(self.seed)
        N = len(X)
        self.estimator_means_ = []
        for _ in range(self.n_estimators):
            indices = rng.integers(0, N, size=N)
            y_boot = y[indices]
            self.estimator_means_.append(y_boot.mean())
        return self

    def predict(self, X: np.ndarray) -> np.ndarray:
        preds = np.array(self.estimator_means_)  # (n_estimators,)
        avg_pred = preds.mean()
        return np.full(len(X), avg_pred)
